patches.find:
body {
  margin: 0;
  background:
    radial-gradient(circle at 0% 0%, #11271d 0%, transparent 42%),
    radial-gradient(circle at 100% 100%, #0b1712 0%, transparent 46%),
    var(--bg);
  color: var(--ink);
  font-family: "Trebuchet MS", "Segoe UI", sans-serif;
}

patches.replace:
body {
  margin: 0;
  background:
    radial-gradient(circle at 10% 0%, #1b2f44 0%, transparent 45%),
    radial-gradient(circle at 100% 100%, #111a24 0%, transparent 55%),
    var(--bg);
  color: var(--ink);
  font-family: "Verdana", "Segoe UI", sans-serif;
}

patches.find:
.app {
  width: min(1080px, 96vw);
  margin: 0 auto;
  padding: 0.55rem;
  display: grid;
  gap: 0.65rem;
}

patches.replace:
.app {
  width: min(1220px, 97vw);
  margin: 0 auto;
  padding: 0.45rem;
  display: grid;
  gap: 0.5rem;
}

patches.find:
.card {
  background: linear-gradient(180deg, #0a1b12, var(--panel));
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 0.65rem;
  box-shadow: 0 8px 20px rgb(0 0 0 / 20%);
}

patches.replace:
.card {
  background: linear-gradient(180deg, #122131, var(--panel));
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 0.6rem;
  box-shadow: 0 12px 28px rgb(0 0 0 / 26%);
}

patches.find:
button {
  border: 1px solid var(--border);
  background: #0b2417;
  color: var(--ink);
  border-radius: 7px;
  padding: 0.5rem 0.78rem;
  font-weight: 700;
  cursor: pointer;
}

patches.replace:
button {
  border: 1px solid var(--border);
  background: linear-gradient(180deg, #163047, #102639);
  color: var(--ink);
  border-radius: 8px;
  padding: 0.48rem 0.72rem;
  font-weight: 700;
  letter-spacing: 0.01em;
  cursor: pointer;
}

patches.find:
.log {
  background: #050b08;
  border: 1px solid #1d3c2b;
  border-radius: 7px;
  padding: 0.5rem;
  max-height: 180px;
  overflow: auto;
}

patches.replace:
.log {
  background: #09121a;
  border: 1px solid #294660;
  border-radius: 8px;
  padding: 0.45rem;
  max-height: 260px;
  overflow: auto;
}
